%% tut_1.m
%% Enter your code here.

M5 = [1, 4, -1, -2; -1, 11, -9, -13];
M6 = [-3 1 -7 5 ; 70 21 110 -35];
M7 = [-6 4 -2 1; 40 30 -22 85];

M = M6;
least_squares(M); %[output:1e9bfc8b] %[output:8c9c972a] %[output:744d20db] %[output:6613ca7f] %[output:728160e3]


function least_squares(M)
x = M(1, :);
y = M(2, :);
J = [1 1 1 1; x]'
H = J' * J
b = J' * y'

p = H \ b % this is inv(H) * b
a = p(1);
b = p(2);
plot(x, y, 'bo');
hold('on');
xs = linspace(min(x)-1, max(x)+1, 1000);
ys = a + b .* xs;
plot(xs, ys, 'r-');
hold('off');
end

